import { useState } from "react";
import { Link } from "react-router-dom";
import AppShell from "../components/AppShell";
import DataTable from "../components/DataTable";
import EmptyState from "../components/EmptyState";
import MetricCard from "../components/MetricCard";
import PageHeader from "../components/PageHeader";
import PrimaryButton from "../components/PrimaryButton";
import SearchFilterBar from "../components/SearchFilterBar";
import SectionCard from "../components/SectionCard";
import SegmentTabs from "../components/SegmentTabs";
import { useVitalPulse } from "../context/VitalPulseContext";
import { formatDateTime } from "../utils/formatters";

export default function PatientsPage() {
  const { latestReading, derived } = useVitalPulse();
  const [tab, setTab] = useState("All");
  const [search, setSearch] = useState("");

  const rows = latestReading
    ? [
        {
          id: latestReading.timestamp,
          patient: <div className="vp-person-cell"><div className="vp-avatar">VP</div><div><strong>Unmapped patient</strong><span>Registry endpoint required</span></div></div>,
          patientId: "Unavailable",
          demographics: "No patient demographics endpoint",
          location: "No facility location endpoint",
          device: latestReading.device_id || "Unavailable",
          heartRate: latestReading.heart_rate,
          temperature: latestReading.temperature,
          spo2: latestReading.spo2,
          risk: derived.riskLabel,
          lastReading: formatDateTime(latestReading.timestamp),
          status: derived.deviceState,
          actions: <Link className="vp-table-link" to="/patients/telemetry-source">View details</Link>,
        },
      ]
    : [];

  return (
    <AppShell topbarAction={<PrimaryButton disabled>Add Patient endpoint required</PrimaryButton>}>
      <PageHeader
        title="Patients"
        subtitle="Manage monitored patients and clinical risk status."
        tabs={
          <SegmentTabs
            tabs={["All", "Active", "Warning", "Critical", "Recovered", "Unassigned device"]}
            value={tab}
            onChange={setTab}
          />
        }
        filters={
          <SearchFilterBar
            searchValue={search}
            onSearchChange={setSearch}
            searchPlaceholder="Search by patient ID or name"
            filters={[
              { label: "Status", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "Status endpoint required" }] },
              { label: "Risk", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "Risk filter endpoint required" }] },
              { label: "Device", value: "all", disabled: true, onChange: () => {}, options: [{ value: "all", label: "Device registry endpoint required" }] },
            ]}
            showExport
            exportDisabled
            onClear={() => setSearch("")}
          />
        }
      />

      <div className="vp-grid vp-grid-metrics">
        <MetricCard icon="patients" label="Total patients" value="Endpoint required" helper="Patient registry not exposed by backend" status="Pending" />
        <MetricCard icon="monitor" label="Active monitoring" value={latestReading ? "1 live telemetry source" : "No live stream"} helper="Derived from monitoring endpoint" status={latestReading ? "Online" : "Pending"} />
        <MetricCard icon="alerts" label="Warning patients" value="Unavailable" helper="Needs patient-risk mapping" status="Pending" />
        <MetricCard icon="risk" label="Critical patients" value="Unavailable" helper="Needs patient-risk mapping" status="Pending" />
        <MetricCard icon="clock" label="Recently updated" value={latestReading ? "1" : "0"} helper={latestReading ? formatDateTime(latestReading.timestamp) : "No recent reading"} status={latestReading ? "Loaded" : "Pending"} />
      </div>

      <SectionCard title="Patient Registry" subtitle="Clinical monitoring roster, assignment status, and latest vitals.">
        {rows.length ? (
          <DataTable
            columns={[
              { key: "patient", label: "Patient" },
              { key: "patientId", label: "Patient ID" },
              { key: "demographics", label: "Age / Gender" },
              { key: "location", label: "Location" },
              { key: "device", label: "Device" },
              { key: "heartRate", label: "Latest HR" },
              { key: "temperature", label: "Latest Temp" },
              { key: "spo2", label: "Latest SpO2" },
              { key: "risk", label: "Risk", type: "badge" },
              { key: "lastReading", label: "Last reading" },
              { key: "status", label: "Status", type: "badge" },
              { key: "actions", label: "Actions" },
            ]}
            rows={rows}
            emptyTitle="No patients available"
            emptyMessage="No patient data has been exposed by the backend yet."
          />
        ) : (
          <EmptyState
            title="No patient registry endpoint"
            message="This screen is fully redesigned, but real patient records cannot be shown until the backend exposes a patients API."
            actionLabel="Endpoint required"
            actionDisabled
          />
        )}
      </SectionCard>
    </AppShell>
  );
}
